import { configureStore } from '@reduxjs/toolkit';


const reducer = {};

const preloadedState = {};

const middleware = [];

const store = configureStore({
    reducer,
    preloadedState,
    middleware: (getDefaultMiddleware) => getDefaultMiddleware().concat(middleware),
});

export default store;
